const allInputs = $input.all();
const articles = [];
const seenTitles = new Set();

for (const inputItem of allInputs) {
  const xmlData = inputItem.json?.data || '';
  const url = inputItem.json?.url || '';
  let source = 'News';
  if (url.includes('bbc')) source = 'BBC';
  else if (url.includes('investing')) source = 'Investing';
  else if (url.includes('cointelegraph')) source = 'Crypto';

  const itemRegex = /<item>[\s\S]*?<\/item>/g;
  let match;
  while ((match = itemRegex.exec(xmlData)) !== null) {
    const item = match[0];
    const titleMatch = item.match(/<title><!\[CDATA\[([^\]]+)\]\]><\/title>|<title>([^<]+)<\/title>/);
    const title = titleMatch ? (titleMatch[1] || titleMatch[2] || '').trim() : '';
    const descMatch = item.match(/<description><!\[CDATA\[([^\]]+)\]\]><\/description>|<description>([^<]+)<\/description>/);
    const description = descMatch ? (descMatch[1] || descMatch[2] || '').trim() : '';
    if (title && !seenTitles.has(title.toLowerCase())) {
      seenTitles.add(title.toLowerCase());
      articles.push({ source, title, description: description.substring(0, 500) });
    }
  }
}

// Helper: check if keyword appears as whole word or phrase
const matchesKeyword = (text, keywords) => {
  for (const kw of keywords) {
    if (kw.includes(' ')) {
      if (text.includes(kw)) return true;
    } else {
      const regex = new RegExp(`\\b${kw}\\b`, 'i');
      if (regex.test(text)) return true;
    }
  }
  return false;
};

// USA politics keywords ONLY - no ambiguous terms that match other contexts
const usaPoliticsKeywords = [
  'trump', 'biden', 'harris', 'obama', 'pelosi', 'mcconnell', 'schumer', 'mccarthy',
  'congress', 'senate', 'house of representatives', 'white house', 'supreme court', 'capitol',
  'democrat', 'republican', 'democrats', 'republicans', 'gop',
  'federal reserve', 'attorney general', 'department of justice', 'impeachment',
  'us election', 'u.s. election', 'presidential election', 'midterm election', 'primary election'
];
const worldKeywords = [
  'ukraine', 'russia', 'gaza', 'israel', 'palestine', 'iran', 'china', 'north korea', 'syria', 'lebanon',
  'germany', 'france', 'britain', 'uk ', 'europe', 'eu ', 'japan', 'south korea', 'india', 'brazil',
  'nato', 'united nations', 'war', 'conflict', 'treaty', 'summit', 'foreign minister', 'prime minister',
  'earthquake', 'hurricane', 'typhoon', 'disaster'
];
const financialKeywords = [
  'stock market', 'wall street', 'dow jones', 's&p 500', 'nasdaq', 'federal reserve', 'interest rate', 'inflation',
  'gdp', 'recession', 'jobs report', 'unemployment rate', 'earnings report', 'ipo', 'merger', 'acquisition',
  'oil price', 'gas price', 'commodities', 'treasury bond', 'yield curve', 'trade deficit', 'hedge fund',
  'sensex', 'ftse', 'nikkei', 'dax', 'hang seng'
];
const cryptoKeywords = [
  'bitcoin', 'ethereum', 'cryptocurrency', 'blockchain', 'defi', 'nft', 'altcoin', 'token sale', 'btc', 'eth', 'mining',
  'crypto wallet', 'web3', 'stablecoin', 'crypto etf', 'sec crypto', 'coinbase', 'binance'
];

const categories = { world: [], political: [], financial: [], crypto: [] };

for (const article of articles) {
  const text = (article.title + ' ' + article.description).toLowerCase();
  let categorized = false;

  // Check USA politics first - must match USA-specific terms
  if (matchesKeyword(text, usaPoliticsKeywords)) {
    categories.political.push(article);
    categorized = true;
  } else if (matchesKeyword(text, cryptoKeywords)) {
    categories.crypto.push(article);
    categorized = true;
  } else if (matchesKeyword(text, financialKeywords)) {
    categories.financial.push(article);
    categorized = true;
  } else if (matchesKeyword(text, worldKeywords)) {
    categories.world.push(article);
    categorized = true;
  }
  if (!categorized) categories.world.push(article);
}

const selected = {
  world: categories.world.slice(0, 5),
  political: categories.political.slice(0, 5),
  financial: categories.financial.slice(0, 5),
  crypto: categories.crypto.slice(0, 5)
};

// Build prompt with context for meaningful summaries
let promptText = 'You are a news editor. For each headline, write a concise one-sentence summary (max 60 chars) that captures the key fact. Be specific and factual.\n\n';
let articleNum = 1;
for (const [cat, arts] of Object.entries(selected)) {
  if (arts.length > 0) {
    promptText += `=== ${cat.toUpperCase()} ===\n`;
    for (const art of arts) {
      promptText += `${articleNum}. Headline: ${art.title}\n`;
      promptText += `   Context: ${art.description.substring(0, 200)}\n\n`;
      articleNum++;
    }
  }
}
promptText += 'OUTPUT FORMAT - use exactly this structure, no markdown:\n';
promptText += 'WORLD:\n1. [60-char summary]\n2. [60-char summary]\n...\nPOLITICAL:\n1. [60-char summary]\n...\nFINANCIAL:\n1. [60-char summary]\n...\nCRYPTO:\n1. [60-char summary]\n...';

return [{ json: { chatInput: promptText } }];

const input = $input.first().json;
const aiOutput = input.output || input.response || input.text || '';
const lines = aiOutput.split('\n');

const categories = {};
let currentCat = null;

for (const line of lines) {
  const cleanLine = line.trim();
  const catMatch = cleanLine.match(/(?:---+\s*|\*{0,2})(WORLD|POLITICAL|FINANCIAL|CRYPTO)(?:\s*---+|\*{0,2}):?\s*$/i);
  if (catMatch) {
    currentCat = catMatch[1].toUpperCase();
    categories[currentCat] = [];
  } else if (currentCat && cleanLine.length > 0) {
    const sumMatch = cleanLine.match(/^(\d+)\.\s+(.+)$/);
    if (sumMatch && sumMatch[2].trim().length > 0) {
      categories[currentCat].push(sumMatch[2].trim());
    }
  }
}

// Build improved message format
const now = new Date();
const dateStr = now.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });
const timeStr = now.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true });

let message = `📰 **Daily News Brief**\n`;
message += `${dateStr} • ${timeStr} PT\n`;
message += `━━━━━━━━━━━━━━━━\n`;

const catEmojis = { WORLD: '🌍', POLITICAL: '🏛️', FINANCIAL: '💰', CRYPTO: '₿' };
const catNames = { WORLD: 'World News', POLITICAL: 'US Politics', FINANCIAL: 'Finance', CRYPTO: 'Crypto' };

let hasContent = false;
for (const [cat, summaries] of Object.entries(categories)) {
  if (summaries.length > 0) {
    hasContent = true;
    message += `\n${catEmojis[cat] || '•'} **${catNames[cat] || cat}**\n`;
    summaries.slice(0, 5).forEach((s, i) => {
      message += `  ${i + 1}. ${s}\n`;
    });
  }
}

if (!hasContent) {
  message += `\n_No news available at this time._\n`;
}

return [{ json: { content: message } }];
